final:
module counter (
    input clk,
    input reset,
    input enable,
    output reg [3:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q <= 4'b0000;
        else if (enable)
            q <= q + 1;
    end

endmodule
